// ── COMBINAR MENSAJES (Buffer Redis) ─────────────────────────────
const lista = $('Redis Recoger').first().json.Mensajes;
const arr = Array.isArray(lista) ? lista : (lista ? [lista] : []);

const mensajeCombinado = arr.length > 0
  ? arr
      .filter(m => m && m.trim().startsWith('{'))
      .map(m => {
        try { return JSON.parse(m.split('||')[0].trim()).message; }
        catch(e) { return m; }
      })
      .filter(Boolean)
      .join('\n')
  : $('Edit Fields1').first().json.Mensaje;

