  Nombre:        $('Edit Fields1').first().json.Nombre,
  Telefono:      $('Edit Fields1').first().json.Telefono,
  NumeroNegocio: $('Edit Fields1').first().json.NumeroNegocio,
  Mensaje:       mensajeCombinado
} }];

const filas = $input.all();
if (!filas.length) {
  return [{ json: { inventarioFormateado: 'Sin datos de inventario disponibles en este momento.', total: 0 } }];
}
const texto = filas.map((f) => {
  const r = f.json;
  const partes = Object.entries(r)
    .filter(([k, v]) => v !== null && v !== undefined && String(v).trim() !== '' && !k.startsWith('row_'))
    .map(([k, v]) => k + ': ' + v);
  return '\u2022 ' + partes.join(' | ');
}).join('\n');
return [{ json: { inventarioFormateado: texto, total: filas.length } }];

