// LIMPIAR TRAZA DE HERRAMIENTAS
function stripUsedTools(text) {
  let result = text;
  let safety = 0;
  while (result.includes('[Used tools:') && safety < 10) {
    safety++;
    const start = result.indexOf('[Used tools:');
    if (start === -1) break;
    let depth = 0, end = start;
    for (let i = start; i < result.length; i++) {
      const ch = result[i];
      if (ch === '[' || ch === '{') depth++;
      else if (ch === ']' || ch === '}') { depth--; if (depth === 0) { end = i + 1; break; } }
    }
    result = (result.slice(0, start) + result.slice(end)).trimStart();
  }
  return result.trim();
}

const UMBRAL_PRESUPUESTO = 20000;
const VALOR_POR_PIEZA    = 2500;
const UMBRAL_PIEZAS      = 8;

const rawOutput     = $input.first().json.output || '';
const output        = stripUsedTools(rawOutput);
const clientMessage = $('Combinar Mensajes').first().json.Mensaje || '';
const waId          = $('Combinar Mensajes').first().json.Telefono;
const clientName    = $('Combinar Mensajes').first().json.Nombre || 'Cliente';
const numNegocio    = $('Combinar Mensajes').first().json.NumeroNegocio;

// -- DETECTAR NUMERO DE PIEZAS/LLANTAS (cliente + bot) --
function detectarPiezas(texto) {
  let max = 0;
  const patrones = [
    /(necesito|ocupo|quiero|busco|son|para)\s+(\d+)\s*(llantas?|piezas?|neum[aá]ticos?|rines?|juegos?)/gi,
    /(\d+)\s*(llantas?|piezas?|neum[aá]ticos?|rines?)/gi,
    /flotilla\s+de\s+(\d+)/gi,
    /(\d+)\s*(camionetas?|camiones?|autos?|coches?|veh[ií]culos?|unidades?)/gi,
  ];
  for (const p of patrones) {
    const matches = [...texto.matchAll(p)];
    for (const m of matches) {
      const nums = m[0].match(/\d+/g);
      if (nums) {
        const total = nums.reduce((s, n) => s + parseInt(n), 0);
        if (total > max) max = total;
      }
    }
  }
  return max;
}

const piezasCliente = detectarPiezas(clientMessage);
const piezasBot     = detectarPiezas(output);
const piezasDetectadas = Math.max(piezasCliente, piezasBot);
const presupuestoEstimadoGrupo = piezasDetectadas * VALOR_POR_PIEZA;
const grupoGrande = piezasDetectadas >= UMBRAL_PIEZAS;

// -- INTENCION DE COMPRA --
const tieneMarkerCompra = output.includes('[INTENCION_COMPRA]');
const keywordsCompra = /\b(quiero comprar|quiero apartar|me lo llevo|c[oó]mo pago|c[oó]mo aparto|cu[aá]nto (sale|cuesta|est[aá]|me queda|nos sale|salen|cuestan)|qu[eé] precio|hay disponibilidad|tienen disponible|est[aá] disponible|tienen en stock|manejan la medida|tienen la medida|meses sin intereses|pago con tarjeta|aceptan tarjeta|dan factura|ocupo factura|necesito factura|me cotizas|cotizaci[oó]n|quiero cotizar|me mandas info|m[aá]ndame info|env[ií]ame info|me interesa|s[ií] me interesa|quiero saber m[aá]s|d[aá]me m[aá]s info|cu[aá]ndo puedo ir|puedo ir hoy|a qu[eé] hora abren|hacen alineaci[oó]n|hacen balanceo|cambio de aceite|revisan frenos|amortiguadores|suspensi[oó]n|ponchadura|se me ponch[oó]|llanta ponchada|refacci[oó]n|medida \d|r1[3-9]|r2[0-2]|\d{3}\/\d{2})\b/i;
const tieneKeywordCompra = keywordsCompra.test(clientMessage);
const intencionCompra = tieneMarkerCompra || tieneKeywordCompra;

// -- PRESUPUESTO ALTO --
const tieneMarkerPresupuesto = output.includes('[PRESUPUESTO_ALTO]');
let isHighBudgetFromMessage = false;

const matchesMil = [...clientMessage.matchAll(/(\d+[\d,\.]*)[\s ]*(mil|k)\b/gi)];
for (const m of matchesMil) {
  const amount = parseFloat(m[1].replace(/[,]/g, '')) * 1000;
  if (amount >= UMBRAL_PRESUPUESTO) { isHighBudgetFromMessage = true; break; }
}
if (!isHighBudgetFromMessage) {
  const matchesMillon = [...clientMessage.matchAll(/(\d+[\d,\.]*)[\s ]*(millones?)/gi)];
  for (const m of matchesMillon) {
    const amount = parseFloat(m[1].replace(/[,]/g, '')) * 1000000;
    if (amount >= UMBRAL_PRESUPUESTO) { isHighBudgetFromMessage = true; break; }
  }
}
if (!isHighBudgetFromMessage) {
  const matchesDirecto = [...clientMessage.matchAll(/[$]?([\d]{1,3}(?:[,\.][\d]{3})+|[\d]{5,})/g)];
  for (const m of matchesDirecto) {
    const amount = parseFloat(m[1].replace(/[,\.]/g, '').replace(/\.(\d{2})$/, ''));
    if (amount >= UMBRAL_PRESUPUESTO) { isHighBudgetFromMessage = true; break; }
  }
}
const keywordsFlotilla = /\b(flotilla|flota|empresa|corporativo|mayoreo|medio mayoreo|camiones|tr[aá]iler|plataforma|reparto|log[ií]stica|transporte)\b/i;
const presupuestoAlto = tieneMarkerPresupuesto || isHighBudgetFromMessage || keywordsFlotilla.test(clientMessage) || grupoGrande;

// -- QUIERE HABLAR CON ASESOR --
const tieneMarkerAsesor = output.includes('[QUIERE_ASESOR]');
const keywordsAsesor = /\b(quiero hablar con (un |una )?(asesor|asesora|persona|humano|alguien)|hablar con (un |una )?(asesor|asesora|persona|alguien|humano)|me comunicas con|me comunica con|p[aá]same con|necesito (un |una )?(asesor|asesora|persona|humano)|quiero (un |una )?(asesor|asesora|agente)|asesor(a)? por favor|agente por favor|persona real|alguien de verdad|hablar con alguien)\b/i;
const quiereAsesor = tieneMarkerAsesor || keywordsAsesor.test(clientMessage);

// -- CANSADO / FRUSTRADO DEL BOT --
const tieneMarkerCansado = output.includes('[CANSADO_BOT]');
const keywordsCansado = /\b(no me (est[aá]s |eres )?(ayudando|sirviendo|entendiendo|resolviendo)|no entiendes|no me entiendes|no sirves|eres (un |)bot|esto no (sirve|funciona|me ayuda)|no funciona(s)?|in[uú]til|no (me )resuelves|ya me cans[eé]|me est[aá]s cansando|me desesper[eé]|harto del bot|harta del bot|est[aá]s en loop|sigues repitiendo|siempre lo mismo|no contestas lo que pregunto)\b/i;
const cansadoBot = tieneMarkerCansado || keywordsCansado.test(clientMessage);

// -- BOT RESPONDIO CON FRASE DE ESCALACION --
const frasesEscalacionBot = /(asesor(a)? (se pondr[aá]|te pondr[aá]|pondr[aá]) en contacto|asesor(a)? te (contactar[aá]n?|atiende|atender[aá]n?|ayudar[aá]n?|llamar[aá]n?|enviar[aá]n?|env[ií]e)|te contactar[aá]n?|nos pondremos en contacto|nos comunicaremos contigo|un(a)? (asesora|asesor) te (llamar[aá]n?|contactar[aá]n?|atender[aá]n?|enviar[aá]n?|env[ií]e|aparta)|pasar(le|te|los)? (tus |los |la )?(datos|informaci[oó]n|solicitud)|voy a pasar(te|los|le)?|te dar[aá]n? seguimiento|coordinar(emos)? (una )?(llamada|cita|visita)|asesor(a)? personal te|nuestro equipo te (contactar[aá]|llamar[aá]|atender[aá])|para (confirmar|cerrar|apartar) (los detalles|tu compra|tus piezas|tu pedido))/i;
const botEscalo = frasesEscalacionBot.test(output);

// -- RESULTADO COMBINADO --
const necesitaAsesor = intencionCompra || presupuestoAlto || quiereAsesor || cansadoBot || botEscalo;

const motivo = presupuestoAlto
               ? (grupoGrande ? 'FLOTILLA/MAYOREO (' + piezasDetectadas + ' piezas ~ $' + presupuestoEstimadoGrupo.toLocaleString() + ')' : 'PRESUPUESTO ALTO')
             : intencionCompra ? 'INTENCION DE COMPRA'
             : quiereAsesor    ? 'QUIERE HABLAR CON ASESOR'
             : cansadoBot      ? 'CANSADO DEL BOT'
             : botEscalo       ? 'BOT ESCALO EN RESPUESTA'
             : '';

// -- ROTACION 3 ASESORES (round-robin a2 -> a3 -> a4) --
const staticData = $getWorkflowStaticData('global');
const CICLO = ['a2', 'a3', 'a4'];
const turnoActual = staticData.turno_asesor || 'a2';
if ((intencionCompra || quiereAsesor || cansadoBot || botEscalo) && !presupuestoAlto) {
  const idx = CICLO.indexOf(turnoActual);
  staticData.turno_asesor = CICLO[(idx + 1) % CICLO.length];
}

// -- LIMPIAR MARCADORES --
const mensajeLimpio = output
  .replace('[INTENCION_COMPRA]', '')
  .replace('[PRESUPUESTO_ALTO]', '')
  .replace('[QUIERE_ASESOR]', '')
  .replace('[CANSADO_BOT]', '')
  .trim();

return [{
  json: {
    output:                mensajeLimpio,
    mensaje_limpio:        mensajeLimpio,
    necesita_asesor:       necesitaAsesor,
    intencion_compra:      intencionCompra,
    presupuesto_alto:      presupuestoAlto,
    quiere_asesor:         quiereAsesor,
    cansado_bot:           cansadoBot,
    bot_escalo:            botEscalo,
    grupo_grande:          grupoGrande,
    piezas_detectadas:     piezasDetectadas,
    presupuesto_estimado:  presupuestoEstimadoGrupo,
    motivo_alerta:         motivo,
    turno_asesor:          turnoActual,
    wa_id:                 waId,
    cliente_nombre:        clientName,
    cliente_mensaje:       clientMessage,
    numero_negocio:        numNegocio
  }
}];

