  if (Array.isArray(items) && items.length > 0) {
    for (const contacto of items) {
      const tags = contacto.tags || contacto.tagIds || [];

      console.log('Contacto:', contacto.phoneNumber,
                  '| tags:', JSON.stringify(tags));

      // YCloud puede devolver tags como:
      //   [{id:"xxx", name:"conocido"}]  ← objetos con name
      //   ["id_abc", "id_def"]           ← solo IDs (strings)
      //   [{tagId:"xxx", tagName:"..."}] ← otro formato
      const tieneTag = tags.some(t => {
        if (typeof t === 'string') {
          // Es un ID, no podemos comparar por nombre
          // Si SOLO hay strings, asumimos que cualquier tag = conocido
          return true;
        }
        // Es objeto: buscar por nombre
        const nombre = (t.name || t.tagName || t.label || '').toLowerCase();
        return nombre.includes(TAG_BUSCAR.toLowerCase());
      });

      if (tieneTag) {
        esConocido = true;
        console.log('→ CONOCIDO (tiene tag "' + TAG_BUSCAR + '")');
        break;
      }
    }
  }

  if (!esConocido) {
    console.log('→ NUEVO LEAD (sin tag "' + TAG_BUSCAR + '") para:', base.Telefono);
  }

} catch(e) {
  console.log('Error:', e.message, '→ tratar como nuevo lead');
  esConocido = false;
}

return [{ json: { ...base, esConocido } }];

